Here's the full pattern:

**XAML** — wrap `CollectionView` in a `RefreshView`:

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm):

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false; // signals RefreshView to stop spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync($"detail?id={SelectedItem.Id}");
        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Notes |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Set `false` when done loading |
| `RefreshView.Command` | `RefreshCommand` | Calls your API, repopulates `Items` |
| `SelectedItem` | `SelectedItem` (TwoWay) | Reset to `null` after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Triggers navigation to detail page |
| `ItemsSource` | `Items` | Must be `ObservableCollection<T>` |

**Important details:**
- Always use `ObservableCollection<T>`, not `List<T>`, so the UI updates on add/remove.
- Set `IsRefreshing = false` at the end of your refresh command — otherwise the spinner never stops.
- Reset `SelectedItem = null` after navigating so the user can tap the same item again.
- Set `x:DataType` on `DataTemplate` for compiled bindings and better performance.
